// ── Helpers (also exported for use in AestheticScreen) ────────────────────────

export function inferCat(name) {
  const n = name.toLowerCase()
  if (/\bjacket\b|\bcoat\b|\bvest\b|blazer|parka|anorak|trench|windbreaker|varsity|overcoat|puffer/.test(n)) return 'outerwear'
  if (/\btee\b|t-shirt|\bshirt\b|\btop\b|blouse|hoodie|sweatshirt|jersey|tube|bandeau|bodysuit|corset|bustier|tank|camisole/.test(n)) return 'tops'
  if (/trouser|jeans|\bskirt\b|shorts|legging|chino|overalls/.test(n)) return 'bottoms'
  if (/sweater|knit|cardigan|pullover|crewneck|turtleneck/.test(n)) return 'knitwear'
  if (/sneaker|boot|shoe|loafer|heel|sandal|\bflat\b|mule|clog|trainer|espadrille/.test(n)) return 'footwear'
  if (/\bdress\b|gown|jumpsuit/.test(n)) return 'formalwear'
  if (/jogger|sports bra|track jacket/.test(n)) return 'activewear'
  return 'accessories'
}

export function inferSeasons(name) {
  const n = name.toLowerCase()
  if (/wool|tweed|thermal|fleece|cashmere|overcoat|parka|fur|velvet/.test(n)) return ['fall', 'winter']
  if (/linen|beach|sandal|espadrille/.test(n)) return ['spring', 'summer']
  return ['spring', 'summer', 'fall', 'winter']
}

