// ── Quiz-compatible flat array ────────────────────────────────────────────────
// Consumed by AppContext buildItemQueue alongside CLOTHING_ITEMS from categories.js

export const AESTHETIC_QUIZ_ITEMS = (() => {
  const out = []
  for (const [aId, items] of Object.entries(AESTHETIC_ITEMS)) {
    const gradient = STYLES[aId]?.gradient ?? 'linear-gradient(135deg, #1a1a1a 0%, #333 100%)'
    for (const item of items) {
      const weight = item.type === 'core' ? 3 : item.type === 'statement' ? 2 : 1
      out.push({
        id:          item.id,
        name:        item.name,
        description: item.desc,
        seasons:     inferSeasons(item.name),
        gradient,
        emoji:       TYPE_EMOJI[item.type],
        styleWeights: { [aId]: weight },
        _category:   inferCat(item.name),
      })
    }
  }
  return out
})()
